  ('bookkeeper-moex-01714', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依中華民國記帳士職業道德規範，下列敘述何者錯誤？', '["記帳士得允諾他人以自己名義執行業務", "記帳士對其聘用之人員，應予適當之指導及監督", "記帳士對外有關業務文件，必要時應親自簽名或蓋章", "記帳士執行業務應恪遵記帳士法及有關法令規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01715', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列各項敘述何者不符合記帳士執行業務之倫理道德規範？', '["記帳士不得藉其業務上獲知之秘密，基於對委託人或第三者不良之企圖，而有任何不法行為", "記帳士對於不能勝任之委辦事項，可以先接受，再複委託其他合格記帳士代為處理", "記帳士不得以詆毁同業或其他不正當方法延攬業務", "記帳士如聘雇他記帳士之現職人員，得徵詢他記帳士之意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01716', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '仁愛公司提供下列資料，請您用毛利率法為其估算期末存貨：期初存貨$90,000，進貨$300,000，進貨折 讓$10,000，進貨運費$4,000，銷貨淨額$562,000，銷貨運費$8,000，正常毛利率為45%，則期末存貨估計 數應為：', '["$74,900", "$79,300", "$82,900", "$66,900"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01717', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何種資產之減損損失得迴轉？①不動產  ②存貨  ③專利權  ④商譽', '["僅", "", "", "僅"]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01718', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '會計上通常以「成本」（而非「清算價值」）來列示資產的價值，主要是基於：', '["會計期間假設", "繼續經營假設", "企業個體假設", "貨幣單位衡量假設"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01719', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '八德公司簽發一張3年期、不附息、面額$2,270,000之票據，以購入公平市價為$1,800,000之土地一筆， 則該公司對二者之差價$470,000應如何處理？', '["借記「應付票據折價」，並逐年攤銷為利息費用", "借記「應付票據折價」，並逐年攤銷為土地成本之增加", "貸記「應付票據折價」，並逐年攤銷為購買土地利得", "不予處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01720', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '一般而言，企業為維護專利權而發生訴訟之成本，應如何處理？', '["若勝訴，則資本化；若敗訴，則列為費用", "不論勝訴或敗訴，皆列為費用", "一律資本化", "視公司政策而定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01721', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何者為公司需作必要調整分錄之相關會計假設、原則與基礎？①經濟個體假設  ②會計期間假設', '["繼續經營假設", "歷史成本原則  ⑤收入認列原則  ⑥配合原則  應計基礎", "僅", "⑤⑥"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01722', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年4月1日發行面額$5,000,000、票面利率5%，每年7月1日及1月1日付息之10年期公 司債，加計應計利息後該公司共得款$4,912,500。則該公司債之發行價格為：', '["97.0", "97.3", "97.7", "101.2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01723', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何種金融資產需評估是否減損，且認列之減損金額得迴轉或減少？①以公平價值衡量且公平價值變', '["以攤銷後成本衡量之金融資產", "以成本衡量之金融資產", "備供出售之 金融資產", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
